"""Hybrid retrieval: Qdrant-first with local lexical fallback."""
from __future__ import annotations

import os
from pathlib import Path

from qdrant_client.models import SparseVector
from rank_bm25 import BM25Okapi

from ingestion.embedders.dense_embedder import embed_query
from ingestion.embedders.sparse_embedder import SparseEmbedder, tokenize
from ingestion.loaders.statpearls_loader import load_chunks
from retrieval.qdrant_client import get_qdrant_client

COLLECTION = os.getenv("COLLECTION_NAME", "medical_rag")
DATA_PATH = Path(os.getenv("DATA_PATH", "data/statpearls_chunks.jsonl"))
SPARSE_STATE_PATH = Path(os.getenv("SPARSE_STATE_PATH", "data/sparse_embedder_state.json"))

_sparse_embedder: SparseEmbedder | None = None
_local_docs: list[dict] | None = None
_local_bm25: BM25Okapi | None = None


def _load_local_index() -> tuple[list[dict], BM25Okapi | None]:
    global _local_docs, _local_bm25
    if _local_docs is None:
        if not DATA_PATH.exists():
            _local_docs = []
            _local_bm25 = None
            return _local_docs, _local_bm25
        _local_docs = list(load_chunks(DATA_PATH))
        tokenized = [tokenize(doc.get("contents", doc.get("content", ""))) for doc in _local_docs]
        _local_bm25 = BM25Okapi(tokenized) if tokenized else None
    return _local_docs, _local_bm25


def _get_sparse_embedder() -> SparseEmbedder:
    global _sparse_embedder
    if _sparse_embedder is None:
        if SPARSE_STATE_PATH.exists():
            _sparse_embedder = SparseEmbedder.load(SPARSE_STATE_PATH)
        else:
            docs, _ = _load_local_index()
            texts = [doc.get("contents", doc.get("content", "")) for doc in docs]
            _sparse_embedder = SparseEmbedder().fit(texts or ["medical clinical"])
    return _sparse_embedder


def rrf_fuse(ranked_lists: list[list[dict]], k: int = 60) -> list[dict]:
    """Reciprocal Rank Fusion. score = sum(1 / (rank + k))."""
    scores: dict[str, float] = {}
    docs: dict[str, dict] = {}
    for ranked in ranked_lists:
        for rank, doc in enumerate(ranked, start=1):
            doc_id = doc["doc_id"]
            scores[doc_id] = scores.get(doc_id, 0.0) + 1.0 / (rank + k)
            docs[doc_id] = doc
    return [docs[doc_id] for doc_id in sorted(scores, key=lambda item: -scores[item])]


def _to_hit_dict(hit) -> dict:
    payload = hit.payload or {}
    return {
        "doc_id": payload.get("doc_id", str(hit.id)),
        "title": payload.get("title", ""),
        "content": payload.get("content", ""),
        "source": payload.get("source", "statpearls"),
        "score": float(getattr(hit, "score", 0.0) or 0.0),
    }


def _local_result(doc: dict, score: float) -> dict:
    return {
        "doc_id": doc.get("id", doc.get("doc_id", "")),
        "title": doc.get("title", ""),
        "content": doc.get("content", doc.get("contents", "")),
        "source": doc.get("source", "statpearls"),
        "score": float(score),
    }


def _local_lexical_search(query: str, top_k: int = 10) -> list[dict]:
    docs, bm25 = _load_local_index()
    if not docs or bm25 is None:
        return []

    query_tokens = tokenize(query)
    if not query_tokens:
        return []

    scores = bm25.get_scores(query_tokens)
    ranked = sorted(enumerate(scores), key=lambda item: float(item[1]), reverse=True)
    results: list[dict] = []
    for idx, score in ranked[:top_k]:
        if score <= 0 and results:
            continue
        results.append(_local_result(docs[idx], float(score)))
    return results


def _qdrant_hybrid_search(query: str, top_k: int) -> list[dict]:
    client = get_qdrant_client()
    collection = client.get_collection(COLLECTION)
    if (collection.points_count or 0) <= 0:
        return []

    dense_results = client.query_points(
        collection_name=COLLECTION,
        query=embed_query(query),
        using="dense",
        limit=top_k,
        with_payload=True,
    ).points

    sparse_results = []
    sparse_vector = _get_sparse_embedder().encode_query(query)
    if sparse_vector["indices"]:
        sparse_results = client.query_points(
            collection_name=COLLECTION,
            query=SparseVector(
                indices=sparse_vector["indices"],
                values=sparse_vector["values"],
            ),
            using="sparse",
            limit=top_k,
            with_payload=True,
        ).points

    fused = rrf_fuse(
        [
            [_to_hit_dict(hit) for hit in dense_results],
            [_to_hit_dict(hit) for hit in sparse_results],
        ]
    )
    return fused[:top_k]


def hybrid_search(query: str, top_k: int = 10) -> list[dict]:
    """Dense+sparse Qdrant search, with local lexical fallback if needed."""
    try:
        results = _qdrant_hybrid_search(query, top_k=top_k)
        if results:
            return results
    except Exception:
        pass
    return _local_lexical_search(query, top_k=top_k)

"""LCEL generation chain: prompt | llm | parser."""
from pathlib import Path
from langchain_core.prompts import PromptTemplate
from langchain_core.output_parsers import StrOutputParser
from .llm_router import get_llm

_PROMPTS_DIR = Path(__file__).parent / "prompts"


def _load_prompt(name: str) -> PromptTemplate:
    text = (_PROMPTS_DIR / name).read_text()
    return PromptTemplate.from_template(text)


def build_chain(model_name: str, use_cot: bool = False, mode: str = "rag"):
    """Return an LCEL chain: prompt | llm | parser."""
    if mode in ("graph", "hybrid"):
        prompt = _load_prompt("graph_qa.txt")
    elif use_cot:
        prompt = _load_prompt("cot_medical.txt")
    else:
        prompt = _load_prompt("clinical_qa.txt")
    llm = get_llm(model_name)
    return prompt | llm | StrOutputParser()


async def generate_answer(question: str, context: str, model_name: str, use_cot: bool = False, mode: str = "rag", config=None) -> str:
    chain = build_chain(model_name, use_cot, mode=mode)
    invoke_config = dict(config) if config else {}
    invoke_config["run_name"] = "3_generate_answer"
    return await chain.ainvoke({"question": question, "context": context}, config=invoke_config)

"""LLM Router — Tous les appels LLM passent par ici."""
import os
from langchain_openai import ChatOpenAI


def get_llm(model_name: str = "gemini"):
    """Factory pour obtenir le bon LLM selon le choix utilisateur."""
    if model_name == "biomistral":
        return ChatOpenAI(
            base_url=os.getenv("BIOMISTRAL_URL", "http://llama-cpp:8080/v1"),
            api_key="not-needed",
            model="biomistral",
            temperature=0.0,
            max_tokens=1024,
        )
    elif model_name in ("gemini", "gemini-pro"):
        vertex_model = "gemini-2.5-pro" if model_name == "gemini-pro" else "gemini-2.5-flash"
        project = os.getenv("GOOGLE_CLOUD_PROJECT") or os.getenv("GCP_PROJECT")
        if project:
            from langchain_google_vertexai import ChatVertexAI
            return ChatVertexAI(
                model_name=vertex_model,
                project=project,
                location=os.getenv("GCP_LOCATION", "europe-west1"),
                temperature=0.0,
            )
        api_key = os.getenv("GOOGLE_API_KEY") or os.getenv("GEMINI_API_KEY")
        if not api_key:
            raise ValueError("Neither GOOGLE_CLOUD_PROJECT nor GOOGLE_API_KEY is set.")
        from langchain_google_genai import ChatGoogleGenerativeAI
        return ChatGoogleGenerativeAI(
            model=vertex_model,
            temperature=0.0,
            google_api_key=api_key,
        )
    elif model_name == "gpt4o":
        return ChatOpenAI(
            model="gpt-4o",
            temperature=0.0,
            api_key=os.getenv("OPENAI_API_KEY"),
        )
    raise ValueError(f"Unknown model: {model_name}")

"""LangChain @tool wrappers for retrieval, rerank, generation, graph, and deep search."""
from langchain_core.tools import tool
from retrieval.hybrid_retriever import hybrid_search
from retrieval.reranker import rerank
from retrieval.crag import crag_gate
from retrieval.context_assembler import assemble_context
from generation.generator import generate_answer
from retrieval.knowledge_graph import query_graph
from retrieval.deep_search import search_pubmed, fetch_abstracts


@tool
def search_qdrant(query: str, top_k: int = 10) -> list[dict]:
    """Search the medical knowledge base using hybrid dense+sparse retrieval."""
    return hybrid_search(query, top_k=top_k)


@tool
def rerank_results(query: str, docs: list[dict], top_k: int = 5) -> dict:
    """Rerank retrieved documents using cross-encoder and apply CRAG gate."""
    reranked = rerank(query, docs, top_k=top_k)
    filtered, is_confident = crag_gate(reranked)
    return {"docs": filtered, "is_confident": is_confident}


@tool
async def generate_answer_tool(question: str, context: str, model_name: str = "gemini") -> str:
    """Generate a cited answer from context using the specified LLM."""
    return await generate_answer(question, context, model_name)


@tool
def search_knowledge_graph(entity: str) -> str:
    """Cherche les relations d'une entité médicale dans PrimeKG
    (maladies, médicaments, symptômes, interactions).
    """
    from api.main import app
    G = app.state.kg
    results = query_graph(G, entity)
    if not results:
        return f"Aucune donnée pour '{entity}' dans le graph."
    grouped: dict[str, list[str]] = {}
    for r in results[:20]:
        rel = r["relation"]
        if rel not in grouped:
            grouped[rel] = []
        grouped[rel].append(f"{r['entity']} [{r['type']}]")
    lines = [f"Knowledge graph — '{entity}' :"]
    for rel, entities in grouped.items():
        lines.append(f"  [{rel}] : {', '.join(entities)}")
    return "\n".join(lines)


@tool
def deep_search_pubmed(query: str) -> str:
    """Recherche web sur PubMed : 36M+ articles médicaux peer-reviewed.
    Utilisé quand le mode Deep Search est activé.
    """
    results = search_pubmed(query, max_results=5)
    if not results:
        return "Aucun article trouvé sur PubMed."
    pmids = [r["pmid"] for r in results]
    abstracts = fetch_abstracts(pmids)
    lines = []
    for r in results:
        abstract = abstracts.get(r["pmid"], "Pas d'abstract.")
        lines.append(
            f"[PMID:{r['pmid']}] {r['title']}\n"
            f"  {r['authors']} — {r['journal']} ({r['date']})\n"
            f"  {abstract[:300]}..."
        )
    return "\n\n".join(lines)

"""Langfuse observability — optional. No-ops if keys are not set."""
import os
import uuid


def langfuse_enabled() -> bool:
    return bool(os.getenv("LANGFUSE_PUBLIC_KEY") and os.getenv("LANGFUSE_SECRET_KEY"))


def create_langfuse_handler():
    """Create a NEW CallbackHandler per request with a unique trace_id."""
    if not langfuse_enabled():
        return None
    from langfuse.langchain import CallbackHandler
    trace_id = uuid.uuid4().hex  # 32 lowercase hex chars
    return CallbackHandler(trace_context={"trace_id": trace_id})

